  "intent": "sector_comparison",
  "tickers_or_sectors": "sector:Information Technology,sector:Energy",
  "time_window": {
    "start": "2017-01",
    "end": "2021-12",
    "note": "Full available coverage in the CSVs; matches user's requested 2017–2021 window."
  },
  "quantitative_questions": [
    "Compute equal-weighted monthly sector return series for Information Technology and Energy from 2017-01 to 2021-12 (use tickerlist.csv to map tickers to sectors and returns.csv for monthly returns).",
    "Calculate total cumulative return and annualized return for each sector over the full 2017–2021 window using the equal-weighted sector series.",
    "Compute annualized volatility (standard deviation of monthly returns annualized) and monthly Sharpe ratio (assume 0% risk-free rate; use monthly mean / monthly std then annualize) for each sector for 2017–2021.",
    "Calculate max drawdown for each sector over the 2017–2021 window from the equal-weighted cumulative return series, and identify the dates of peak and trough for each max drawdown.",
    "Identify top 5 and bottom 5 tickers within each sector by total return over 2017–2021 and compute each ticker's contribution to the sector's equal-weighted cumulative return (show both absolute contribution and ranked list)."
  ],
  "qualitative_questions": [
    "What macro and commodity-specific factors (oil price cycles, OPEC+/supply shocks, demand collapse in 2020) explain Energy sector performance during 2017–2021?",
    "What secular/industry drivers (cloud adoption, software/platform monetization, multiple expansion for large-cap tech, COVID-driven digital acceleration) and company-specific events explain Information Technology out- or under-performance in that period?"
  ],
  "chart_requests": [
    {
      "chart_id": "sector_cumulative_returns",
      "chart_type": "line",
      "description": "Plot cumulative return (starting at 100) of equal-weighted Information Technology and Energy sector series monthly from 2017-01 to 2021-12 on the same axes; include legend, grid, and vertical shading for 2020 (COVID shock) to emphasize drawdown/recovery differences."
    },
    {
      "chart_id": "sector_return_volatility_scatter",
      "chart_type": "scatter",
      "description": "Scatter plot with x-axis = annualized volatility and y-axis = annualized return for Information Technology and Energy over 2017–2021 (one point per sector). Annotate points with sector names and include lines showing equal-return or equal-risk reference if helpful."
    },
    {
      "chart_id": "sector_rolling_12m_returns",
      "chart_type": "line",
      "description": "Plot rolling 12-month cumulative/total return for both sectors from 2017-01 through 2021-12 (monthly steps) to show changing performance over time; include legend and highlight periods where one sector led the other."
    },
    {
      "chart_id": "sector_max_drawdown_timeline",
      "chart_type": "bar",
      "description": "Bar chart comparing max drawdown values for Information Technology and Energy over 2017–2021 with annotations showing peak and trough dates for each drawdown (bars = drawdown magnitude in %)."
    },
    {
      "chart_id": "top_bottom_contributors_by_sector",
      "chart_type": "bar",
      "description": "Two grouped horizontal bar charts (one per sector) showing the top 5 positive and bottom 5 negative tickers by total return over 2017–2021; include each ticker's absolute total return (%) and its contribution to the sector's equal-weighted cumulative return."
    }
  ],
  "presentation_angle": "Demonstrate that Information Technology materially out/under-performed Energy from 2017–2021 (quantified by cumulative return, volatility, drawdown and rolling returns), and separate quantitative attribution (constituent-level contributions and timing) from qualitative macro and industry explanations (commodity cycle and COVID impacts for Energy vs secular demand and multiple effects for Technology).",
  "out_of_scope_notes": "All quantitative analysis will use equal-weighted sector aggregates because tickerlist.csv does not provide market-cap or sector weights; capitalization-weighted sector results are not possible from the available CSVs. Explanations about macro causes, policy, commodity fundamentals, or company-specific news/events require external sources and cannot be answered from the CSVs alone."
}

